// submit.js — Part 4: Backend integration + Modern Right Panel
import { useState } from 'react';
import { useStore } from './store';
import { shallow } from 'zustand/shallow';
import { NODE_CONFIGS } from './nodes/nodeConfigs';

export const RightPanel = () => {
  const { nodes, edges, logs, addLog } = useStore(
    (state) => ({
      nodes: state.nodes,
      edges: state.edges,
      logs: state.logs,
      addLog: state.addLog,
    }),
    shallow
  );
  const [loading, setLoading] = useState(false);

  // Find the selected node
  const selectedNode = nodes.find((n) => n.selected);

  // Count active LLM agents
  const activeAgents = nodes.filter((n) => n.type === 'llm').length;

  const handleSubmit = async () => {
    setLoading(true);
    const timeStr = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    try {
      const res = await fetch('http://localhost:8000/pipelines/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodes, edges }),
      });
      const data = await res.json();

      // Append a run log
      addLog({
        id: `log-${Date.now()}`,
        text: `Run Pipeline: ${data.is_dag ? 'Success (DAG)' : 'Cycles Found'}`,
        status: data.is_dag ? 'success' : 'warning',
        time: `${timeStr} (${nodes.length} nodes, ${edges.length} edges)`,
      });

      // Browser alert displaying values
      alert(
        `Pipeline Analysis Results:\n` +
        `-----------------------------------------\n` +
        `• Total Nodes: ${data.num_nodes}\n` +
        `• Total Edges: ${data.num_edges}\n` +
        `• Directed Acyclic Graph (DAG): ${data.is_dag ? 'Yes (✓ Valid)' : 'No (✗ Contains Cycles)'}`
      );
    } catch (err) {
      addLog({
        id: `log-${Date.now()}`,
        text: 'Run Pipeline failed (Network error)',
        status: 'error',
        time: timeStr,
      });
      alert('Error: Could not connect to the backend. Is the server running?');
    } finally {
      setLoading(false);
    }
  };

  const handleFieldChange = (nodeId, key, value) => {
    useStore.getState().updateNodeField(nodeId, key, value);
  };

  return (
    <div className="right-panel">
      {/* ── Workspace Overview & Status ── */}
      <div className="panel-card">
        <h3 className="panel-card-title">Workspace Overview & Status</h3>
        <div className="status-grid">
          <div className="status-row">
            <span>Agents Active</span>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <span className="status-value">{activeAgents}</span>
              <span className="status-dot success" />
            </div>
          </div>
          <div className="status-row">
            <span>Total Nodes</span>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <span className="status-value">{nodes.length}</span>
              <span className="status-dot warning" />
            </div>
          </div>
        </div>
      </div>

      {/* ── Recent Logs ── */}
      <div className="panel-card scrollable-card">
        <h3 className="panel-card-title">Recent Logs</h3>
        <div className="logs-list">
          {logs.map((log) => (
            <div key={log.id} className="log-item">
              <div className="log-header">
                <span className={`log-indicator ${log.status}`} />
                <span className="log-text">{log.text}</span>
              </div>
              <span className="log-time">{log.time}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ── Active Node Editor ── */}
      <div className="panel-card editor-card">
        <h3 className="panel-card-title">Active Node Editor</h3>
        {selectedNode ? (
          <div className="editor-fields">
            <div className="editor-node-header">
              <span className="editor-node-icon" style={{ backgroundColor: NODE_CONFIGS[selectedNode.type]?.color || '#7c3aed' }}>
                {NODE_CONFIGS[selectedNode.type]?.icon || '⚙️'}
              </span>
              <div className="editor-node-info">
                <div className="editor-node-name">{selectedNode.id}</div>
                <div className="editor-node-type">
                  {NODE_CONFIGS[selectedNode.type]?.title || selectedNode.type}
                </div>
              </div>
            </div>

            {(NODE_CONFIGS[selectedNode.type]?.fields || []).map((field) => (
              <div key={field.key} className="editor-field">
                <label className="editor-field-label">{field.label}</label>
                {field.type === 'select' ? (
                  <select
                    className="editor-select"
                    value={selectedNode.data?.[field.key] ?? field.defaultValue ?? ''}
                    onChange={(e) => handleFieldChange(selectedNode.id, field.key, e.target.value)}
                  >
                    {(field.options || []).map((opt) => (
                      <option key={opt} value={opt}>
                        {opt}
                      </option>
                    ))}
                  </select>
                ) : field.type === 'textarea' ? (
                  <textarea
                    className="editor-textarea"
                    value={selectedNode.data?.[field.key] ?? field.defaultValue ?? ''}
                    onChange={(e) => handleFieldChange(selectedNode.id, field.key, e.target.value)}
                    placeholder={field.placeholder || ''}
                    rows={4}
                  />
                ) : (
                  <input
                    className="editor-input"
                    type={field.type || 'text'}
                    value={selectedNode.data?.[field.key] ?? field.defaultValue ?? ''}
                    onChange={(e) => handleFieldChange(selectedNode.id, field.key, e.target.value)}
                    placeholder={field.placeholder || ''}
                  />
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="editor-placeholder">
            <span className="editor-placeholder-icon">🖱️</span>
            <p>Select a node on the canvas to inspect and edit its properties.</p>
          </div>
        )}
      </div>

      {/* ── Run Pipeline CTA ── */}
      <button className="run-pipeline-btn" onClick={handleSubmit} disabled={loading}>
        {loading ? '⏳ Analyzing...' : '▶ Run Pipeline'}
      </button>
    </div>
  );
};
